  "cases": [
    {
      "input": {
        "op": "config",
        "config": {
          "domain": "login.example.com",
          "clientID": "sample-client",
          "clientSecret": "sample-secret",
          "callbackURL": "/callback",
          "expectedIssuer": "https://custom.example.org/",
          "authorizationURL": "https://custom.example.org/authorize",
          "tokenURL": "https://custom.example.org/oauth/token",
          "userInfoURL": "https://custom.example.org/userinfo",
          "apiUrl": "https://custom.example.org/api"
        }
      },
      "expected_output": "expectedIssuer=https://custom.example.org/\nauthorizationURL=https://custom.example.org/authorize\ntokenURL=https://custom.example.org/oauth/token\nuserInfoURL=https://custom.example.org/userinfo\napiUrl=https://custom.example.org/api\nstate=true\n"
    }
  ]
}

