Here are the public test cases for feature5_2_issuer:
{
  "description": "Verification requires the issuer claim to be a present string and to equal the expected issuer. A missing issuer yields a neutral issuer-missing category; a present but non-matching issuer yields an issuer-mismatch category carrying the expected and actual issuer values as separate fields.",
  "cases": [
    {
      "input": {
        "op": "verify",
        "header": {
          "alg": "RS256"
        },
        "payload": {
          "sub": "user|abc",
          "aud": "sample-client",
          "exp": 9999999999,
          "iat": 1000000000
        },
        "options": {}
      },
      "expected_output": "error=issuer_missing\n"
    },
    {
      "input": {
        "op": "verify",
        "header": {
          "alg": "RS256"
        },
        "payload": {
          "iss": "https://login.example.com/",
          "sub": "user|abc",
          "aud": "sample-client",
          "exp": 9999999999,
          "iat": 1000000000
        },
        "options": {
          "iss": "https://other.example.com/"
        }
      },
      "expected_output": "error=issuer_mismatch\nexpected=https://other.example.com/\nactual=https://login.example.com/\n"
    }
  ]
}

